{"command": "cd /tmp/sv-e215aa30c1e44eb18347d47173c70743/advanced-multi-complexity && dotnet package list --format json > after-cpm-packages.json 2>&1 && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> version
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return m

b = build_map(baseline)
a = build_map(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<16} {\"Framework\":<10} {\"Package\":<48} {\"Before\":<12} {\"After\":<12}')
    print('-' * 100)
    for c in changes:
        print(f'{c[0]:<16} {c[1]:<10} {c[2]:<48} {c[3]:<12} {c[4]:<12}')
else:
    print('No changes detected')

print()
print(f'UNCHANGED: {len(unchanged)} package-framework entries resolve identically')
"
